r each deadline, all four fields	[-0.063012265,0.04154665,0.0081936065,0.037686106,0.011495084,0.006141392,-0.032907195,0.0040376047,-0.07696367,0.049833782,0.029527288,-0.057088193,0.02898592,-0.02875951,-0.010366167,0.08596129,0.05569521,-0.027021255,-0.11172017,-0.017462285,0.15537876,0.015987448,-0.0038412784,-0.006738033,-0.08158918,-0.0075953547,-0.094386384,-0.055974476,-0.0715036,-0.006993845,-0.00017683153,0.07498586,0.08111196,0.02173867,0.084551275,0.04355864,0.061371323,-0.0023018292,0.007920028,-0.027187152,-0.05185263,-0.0073555307,-0.006277379,0.049545113,-0.037647925,-0.05539106,-0.014357513,-0.06569422,-0.1553428,-0.013043935,-0.044452026,0.023023965,-0.019979514,0.017401777,-0.0042907298,6.729897e-05,0.043561034,-0.018382393,-0.036869556,-0.07156534,-0.073964566,-0.0054065827,-0.1051161,-0.020880345,-0.004291525,0.017092433,-0.04917306,-0.055584725,-0.004483966,-0.007199382,-0.062975086,0.007856696,-0.038916405,0.0042422367,0.005728308,-0.009845208,-0.0036617513,0.08135557,0.046699006,-0.18297297,-0.028766705,0.04576852,0.008647641,0.0049089855,-0.034515113,-0.03200108,-0.018494703,0.044288117,0.028423868,0.086385064,0.049454615,-0.07883312,0.09209274,-0.035608947,0.050016798,0.023826439,-0.0067461138,-0.11167859,0.0049207746,0.040350333,0.0065901102,-0.04061976,0.00061694824,-0.10207205,-0.023186358,-0.037515197,-0.019999048,-0.017681634,-0.0999857,-0.0074622342,0.048055563,-0.012986583,-0.021830225,-0.105787,0.021196963,0.059336103,0.036992688,0.00023709718,0.039950743,-0.0061757523,0.004407566,0.019686196,0.00071708637,0.0006096057,0.061714604,-0.035735723,-0.019653445,6.3019575e-33,0.044395246,0.007630054,-0.06441267,0.044092353,0.03530921,0.030963935,0.04771427,-0.029575925,-0.013200645,0.0007625705,0.020449512,0.07239186,-0.011006311,-0.005389628,0.0024399976,-0.04141226,0.02881348,0.0772467,-0.004717333,0.03989027,0.08694281,-0.03749705,-0.046416804,-0.011853642,0.047209755,0.043688048,-0.027282666,-0.013245603,-0.06289004,0.021251313,-0.015